const crypto = require('crypto');

const signature = $request.headers['x-kiwify-signature'];
const secret = $env.KIWIFY_WEBHOOK_SECRET;

if (!secret) {
  throw new Error('Security: KIWIFY_WEBHOOK_SECRET env variable not configured');
}

if (!signature) {
  throw new Error('Security Violation: Missing x-kiwify-signature header');
}

// Validate HMAC signature
const rawBody = JSON.stringify($input.first().json);
const expectedSignature = crypto.createHmac('sha256', secret).update(rawBody).digest('hex');

if (signature !== expectedSignature) {
  throw new Error('Security Violation: Invalid webhook signature');
}

return $input.all();

// Idempotency check: prevent duplicate deliveries
const staticData = $getWorkflowStaticData('global');
if (!staticData.processedOrders) {
  staticData.processedOrders = {};
}

const orderId = $json.order_id || $json.body?.order_id;
if (!orderId) {
  throw new Error('Validation Error: Missing order_id in payload');
}

if (staticData.processedOrders[orderId]) {
  // Already processed - return empty to stop workflow
  console.log(`Duplicate order skipped: ${orderId} (originally processed at ${staticData.processedOrders[orderId]})`);
  return [];
}

// Mark as processing (will be confirmed after delivery)
staticData.processedOrders[orderId] = new Date().toISOString();

// Cleanup: remove orders older than 30 days to prevent memory bloat
const thirtyDaysAgo = Date.now() - (30 * 24 * 60 * 60 * 1000);
for (const [id, ts] of Object.entries(staticData.processedOrders)) {
  if (new Date(ts).getTime() < thirtyDaysAgo) {
    delete staticData.processedOrders[id];
  }
}

return $input.all();

// Log successful delivery
const orderId = $json.order_id || $('Check Duplicate Order').first().json.order_id || $('Check Duplicate Order').first().json.body?.order_id;

const logEntry = {
  order_id: orderId,
  timestamp: new Date().toISOString(),
  status: 'delivered',
  delivery_response_status: $json.statusCode || 200
};

console.log('Delivery Success:', JSON.stringify(logEntry));

return [{ json: logEntry }];

// Handle delivery errors
const error = $input.first().json;
const orderId = error.order_id || 'unknown';

const logEntry = {
  order_id: orderId,
  timestamp: new Date().toISOString(),
  status: 'delivery_failed',
  error: error.message || 'Unknown delivery error'
};

console.error('Delivery Failed:', JSON.stringify(logEntry));

return [{ json: logEntry }];
